import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Progress } from 'antd';
import 'antd/dist/reset.css';

const lessonData = {
  1: {
    videoUrl: "https://www.youtube.com/embed/dQw4w9WgXcQ",
    quiz: [
      {
        question: "1. Why should you never use passwords like 'abc123' or 'P@ssw0rd'?",
        options: [
          "Because they look boring",
          "Because they are easy to guess",
          "Because they're too long"
        ],
        answer: 1,
        help: "These passwords are super common and easy for hackers to crack. 🧠"
      }
      // 其他问题...
    ]
  }
  // 其他课程...
};

export default function VideoPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const currentId = parseInt(id || "1");
  const maxLessonId = Object.keys(lessonData).length;
  const nextId = currentId + 1 > maxLessonId ? 1 : currentId + 1;

  const { videoUrl, quiz } = lessonData[currentId] || lessonData[1];
  const [answers, setAnswers] = useState(Array(quiz.length).fill(null));
  const [submitted, setSubmitted] = useState(false);
  const [aiHelpIndex, setAiHelpIndex] = useState(null);

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [id]);

  const handleOptionChange = (index, option) => {
    const newAnswers = [...answers];
    newAnswers[index] = option;
    setAnswers(newAnswers);
  };

  const handleSubmit = () => {
    setSubmitted(true);
    setAiHelpIndex(null);
  };

  const score = answers.reduce((acc, cur, idx) => {
    return cur === quiz[idx].answer ? acc + 2 : acc;
  }, 0);

  return (
    <div className="content-card">
      <div style={styles.container}>
        <h2 style={styles.title}>📹 Lesson {currentId} - Watch & Quiz</h2>

        {/* 视频区域 */}
        <div style={styles.videoWrapper}>
          <iframe
            width="100%"
            height="315"
            src={videoUrl}
            title={`Lesson ${currentId}`}
            frameBorder="0"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
          ></iframe>
        </div>

        {/* 问题区 */}
        <div style={styles.quizSection}>
          {quiz.map((q, index) => (
            <div key={index} style={styles.questionBlock}>
              <p><strong>{q.question}</strong></p>
              {q.options.map((opt, optIdx) => (
                <label key={optIdx} style={styles.option}>
                  <input
                    type="radio"
                    name={`question-${index}`}
                    value={optIdx}
                    disabled={submitted}
                    checked={answers[index] === optIdx}
                    onChange={() => handleOptionChange(index, optIdx)}
                  />
                  {opt}
                </label>
              ))}
              {submitted && answers[index] !== q.answer && (
                <p style={styles.wrong}>❌ Wrong answer</p>
              )}
              <button
                style={styles.helpBtn}
                onClick={() => setAiHelpIndex(index)}
                disabled={submitted && answers[index] === q.answer}
              >
                🤖 Ask AI for help
              </button>
              {aiHelpIndex === index && (
                <div style={styles.aiResponse}>
                  <p><strong>AI:</strong> {q.help}</p>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* 提交与导航 */}
        {!submitted ? (
          <button onClick={handleSubmit} style={styles.submitBtn}>
            Submit
          </button>
        ) : (
          <p style={styles.score}>Your score: {score} / {quiz.length * 2}</p>
        )}

        <button
          onClick={() => navigate(`/video/${nextId}`)}
          style={styles.nextBtn}
        >
          ▶️ Next Lesson →
        </button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    padding: '1.5em',
    fontFamily: 'Arial, sans-serif',
    maxWidth: '800px',
    margin: '0 auto',
  },
  title: {
    textAlign: 'center',
    color: '#00796b',
    marginBottom: '1.5em',
    fontSize: '1.5em'
  },
  videoWrapper: {
    marginBottom: '2em',
    borderRadius: '10px',
    overflow: 'hidden',
    boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
    border: '2px solid #b2ebf2'
  },
  quizSection: {
    marginBottom: '1.5em'
  },
  questionBlock: {
    marginBottom: '2em',
    background: '#f7f7f7',
    padding: '1.2em',
    borderRadius: '10px',
    borderLeft: '4px solid #4fb3bf'
  },
  option: {
    display: 'block',
    margin: '0.8em 0',
    padding: '0.8em',
    background: '#fff',
    borderRadius: '8px',
    cursor: 'pointer',
    transition: 'all 0.2s',
    ':hover': {
      background: '#e1f5fe'
    }
  },
  wrong: {
    color: '#d32f2f',
    fontWeight: 'bold',
    marginTop: '0.5em'
  },
  submitBtn: {
    width: '100%',
    padding: '0.8em',
    background: '#4fb3bf',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    fontSize: '1em',
    cursor: 'pointer',
    transition: 'all 0.2s',
    margin: '1em 0',
    ':hover': {
      background: '#00838f'
    }
  },
  helpBtn: {
    marginTop: '0.8em',
    padding: '0.5em 1em',
    background: '#333',
    color: 'white',
    border: 'none',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '0.9em',
    transition: 'all 0.2s',
    ':hover': {
      background: '#555'
    }
  },
  aiResponse: {
    marginTop: '0.8em',
    background: '#e1f5fe',
    padding: '0.8em',
    borderRadius: '6px',
    borderLeft: '3px solid #0288d1'
  },
  score: {
    textAlign: 'center',
    fontSize: '1.2em',
    fontWeight: 'bold',
    color: '#00796b',
    margin: '1.5em 0'
  },
  nextBtn: {
    display: 'block',
    width: '100%',
    padding: '0.8em',
    background: '#0288d1',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    fontSize: '1em',
    cursor: 'pointer',
    transition: 'all 0.2s',
    margin: '1em 0',
    ':hover': {
      background: '#01579b'
    }
  }
};
